import{_ as a,C as r,o as i,c as s,ag as t,E as d,w as n,a as l}from"./chunks/framework.BZohXCq9.js";const P=JSON.parse('{"title":"Asistente de configuración","description":"El wizard de 5 pasos para crear tu página SYNTIstudio desde cero","frontmatter":{"title":"Asistente de configuración","description":"El wizard de 5 pasos para crear tu página SYNTIstudio desde cero"},"headers":[],"relativePath":"studio/asistente-configuracion.md","filePath":"studio/asistente-configuracion.md"}'),c={name:"studio/asistente-configuracion.md"};function u(p,e,h,g,m,b){const o=r("Note");return i(),s("div",null,[e[1]||(e[1]=t('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El asistente de configuración (wizard) es el proceso guiado de 5 pasos que completas al crear tu negocio en SYNTIstudio. Te lleva desde el nombre de tu negocio hasta tu página publicada.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><code>syntiweb.com/onboarding</code> → selecciona <strong>&quot;Presencia Web Completa&quot;</strong> → se abre el asistente de SYNTIstudio en <code>syntiweb.com/studio</code>.</p><p>El asistente solo se muestra <strong>una vez</strong>, al crear tu negocio. Después, toda la edición se hace desde el panel de administración.</p><h2 id="los-5-pasos" tabindex="-1">Los 5 pasos <a class="header-anchor" href="#los-5-pasos" aria-label="Permalink to &quot;Los 5 pasos&quot;">​</a></h2><h3 id="paso-1-negocio" tabindex="-1">Paso 1: Negocio <a class="header-anchor" href="#paso-1-negocio" aria-label="Permalink to &quot;Paso 1: Negocio&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Nombre del Negocio</strong></td><td>✅ Sí</td><td>El nombre comercial de tu negocio</td></tr><tr><td><strong>Tipo de Negocio</strong></td><td>✅ Sí</td><td>Selección de 21+ categorías: Belleza/Estética, Restaurante, Tienda de Ropa, Salud/Clínica, Academia, Gimnasio, Freelancer, Tecnología, etc.</td></tr><tr><td><strong>Ciudad</strong></td><td>No</td><td>Ciudad donde opera tu negocio</td></tr></tbody></table><h3 id="paso-2-mensaje" tabindex="-1">Paso 2: Mensaje <a class="header-anchor" href="#paso-2-mensaje" aria-label="Permalink to &quot;Paso 2: Mensaje&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Eslogan</strong></td><td>No</td><td>Frase corta que describe tu negocio (aparece en el hero)</td></tr><tr><td><strong>Subtítulo Hero</strong></td><td>No</td><td>Texto secundario debajo del eslogan</td></tr><tr><td><strong>Texto Acerca de</strong></td><td>No</td><td>Descripción larga de tu negocio (sección &quot;Acerca de&quot;)</td></tr></tbody></table><h3 id="paso-3-propuesta" tabindex="-1">Paso 3: Propuesta <a class="header-anchor" href="#paso-3-propuesta" aria-label="Permalink to &quot;Paso 3: Propuesta&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Propuesta de valor 1</strong></td><td>✅ Sí</td><td>Lo que te diferencia #1 (ej: &quot;Atención personalizada&quot;)</td></tr><tr><td><strong>Propuesta de valor 2</strong></td><td>✅ Sí</td><td>Lo que te diferencia #2 (ej: &quot;10 años de experiencia&quot;)</td></tr><tr><td><strong>Propuesta de valor 3</strong></td><td>✅ Sí</td><td>Lo que te diferencia #3 (ej: &quot;Productos importados&quot;)</td></tr></tbody></table><h3 id="paso-4-plan-subdominio" tabindex="-1">Paso 4: Plan + Subdominio <a class="header-anchor" href="#paso-4-plan-subdominio" aria-label="Permalink to &quot;Paso 4: Plan + Subdominio&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Plan</strong></td><td>✅ Sí</td><td>Oportunidad (REF 99/año), Crecimiento (REF 149/año) o Visión (REF 199/año)</td></tr><tr><td><strong>Subdominio</strong></td><td>✅ Sí</td><td>Tu dirección web: <code>tunombre.syntiweb.com</code>. Se valida en tiempo real.</td></tr><tr><td><strong>WhatsApp ventas</strong></td><td>No</td><td>Número de WhatsApp (mínimo 10 dígitos)</td></tr><tr><td><strong>Teléfono</strong></td><td>No</td><td>Número de teléfono fijo o móvil</td></tr><tr><td><strong>Email</strong></td><td>No</td><td>Correo electrónico de contacto</td></tr></tbody></table>',14)),d(o,null,{default:n(()=>[...e[0]||(e[0]=[l(" El subdominio se verifica en tiempo real — si ya está en uso, te lo indica al instante. Elige algo corto y fácil de recordar. Una vez creado, **no se puede cambiar**. ",-1)])]),_:1}),e[2]||(e[2]=t('<h3 id="paso-5-revision" tabindex="-1">Paso 5: Revisión <a class="header-anchor" href="#paso-5-revision" aria-label="Permalink to &quot;Paso 5: Revisión&quot;">​</a></h3><p>Muestra un resumen de todo lo que completaste. Confirmas y se crea tu negocio.</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No permite subir imágenes — eso se hace después en el panel</li><li>No permite agregar productos ni servicios — se agregan desde el panel</li><li>No configura colores ni tema — se elige después en <strong>Cómo Se Ve</strong></li><li>No procesa pago del plan — la activación del plan es un proceso separado</li><li>No se puede volver a ejecutar — es de una sola vez al crear el negocio</li></ul><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-academia-aprende-ya-en-barquisimeto" tabindex="-1">Caso: Academia &quot;Aprende Ya&quot; en Barquisimeto <a class="header-anchor" href="#caso-academia-aprende-ya-en-barquisimeto" aria-label="Permalink to &quot;Caso: Academia &quot;Aprende Ya&quot; en Barquisimeto&quot;">​</a></h3><ol><li><strong>Paso 1 (Negocio):</strong> Nombre: &quot;Aprende Ya&quot; → Tipo: &quot;Academia/Educativo&quot; → Ciudad: &quot;Barquisimeto&quot;</li><li><strong>Paso 2 (Mensaje):</strong> Eslogan: &quot;Tu futuro empieza hoy&quot; → Subtítulo: &quot;Cursos presenciales y online&quot;</li><li><strong>Paso 3 (Propuesta):</strong> &quot;Profesores certificados&quot; / &quot;Horarios flexibles&quot; / &quot;Material incluido&quot;</li><li><strong>Paso 4 (Plan):</strong> Plan Crecimiento (REF 149/año) → Subdominio: <code>aprendeya</code> → WhatsApp: 04241234567</li><li><strong>Paso 5 (Revisión):</strong> Confirma → Página creada en <code>aprendeya.syntiweb.com</code></li></ol><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/panel-administracion.html">Panel de administración</a> — Los 7 tabs para editar tu negocio</li><li><a href="/studio/paletas-de-color.html">Paletas de color</a> — Elige los colores de tu página</li><li><a href="/shared/quickstart.html">Primeros pasos</a> — Guía completa de inicio</li></ul>',9))])}const f=a(c,[["render",u]]);export{P as __pageData,f as default};
